15	// ListAll returns active and stopped sessions discovered from on-disk metadata.
16	func (m *Manager) ListAll(ctx context.Context) ([]*Info, error) {
17		if ctx == nil {
18			return nil, errors.New("session: list context is required")
19		}
20	
21		active := m.List()
22		activeByID := make(map[string]*Info, len(active))
23		for _, info := range active {
24			if info == nil {
25				continue
26			}
27			activeByID[info.ID] = info
28		}
29	
30		entries, err := os.ReadDir(m.homePaths.SessionsDir)
31		switch {
32		case err == nil:
33		case errors.Is(err, os.ErrNotExist):
34			return sortSessionInfos(active), nil
35		default:
36			return nil, fmt.Errorf("session: read sessions directory %q: %w", m.homePaths.SessionsDir, err)
37		}
38	
39		infos := make([]*Info, 0, len(entries)+len(activeByID))
40		seen := make(map[string]struct{}, len(entries))
41		for _, entry := range entries {
42			if err := ctx.Err(); err != nil {
43				return nil, fmt.Errorf("session: list sessions canceled: %w", err)
44			}
45			if !entry.IsDir() {
46				continue
47			}
48	
49			id := strings.TrimSpace(entry.Name())
50			if id == "" {
51				continue
52			}
53	
54			meta, err := m.readMetaWithContext(ctx, id)
55			if err != nil {
56				if errors.Is(err, ErrSessionNotFound) {
57					continue
58				}
59				m.logger.Warn("session: skip unreadable session metadata", "session_id", id, "error", err)
60				if info, ok := activeByID[id]; ok && info != nil {
61					infos = append(infos, info)
62					seen[id] = struct{}{}
63				}
64				continue
65			}
66	
67			info := m.sessionInfoFromMeta(ctx, meta)
68			if activeInfo, ok := activeByID[id]; ok && activeInfo != nil {
69				info = activeInfo
70			}
71			infos = append(infos, info)
72			seen[id] = struct{}{}
73		}
74	
75		for id, info := range activeByID {
76			if _, ok := seen[id]; ok || info == nil {
77				continue
78			}
79			infos = append(infos, info)
80		}
81	
82		return sortSessionInfos(infos), nil
83	}
84	
85	// Status returns the current session status from memory or on-disk metadata.
86	func (m *Manager) Status(ctx context.Context, id string) (*Info, error) {
87		if ctx == nil {
88			return nil, errors.New("session: status context is required")
89		}
90	
91		target := strings.TrimSpace(id)
92		if target == "" {
93			return nil, errors.New("session: session id is required")
94		}
95	
96		if session, ok := m.Get(target); ok {
97			return session.Info(), nil
98		}
99	
100		meta, err := m.readMetaWithContext(ctx, target)
101		if err != nil {
102			return nil, err
103		}
104		return m.sessionInfoFromMeta(ctx, meta), nil
105	}
