153	func (m *Manager) openQueryRecorder(ctx context.Context, id string) (EventRecorder, func() error, error) {
154		if ctx == nil {
155			return nil, nil, errors.New("session: query context is required")
156		}
157	
158		target := strings.TrimSpace(id)
159		if target == "" {
160			return nil, nil, errors.New("session: session id is required")
161		}
162	
163		waited, err := m.waitForSessionFinalization(ctx, target)
164		if err != nil {
165			return nil, nil, fmt.Errorf("session: wait for finalization for %q: %w", target, err)
166		}
167		if !waited {
168			if session, ok := m.Get(target); ok {
169				recorder := session.recorderHandle()
170				if recorder != nil {
171					return recorder, func() error { return nil }, nil
172				}
173				waited, err = m.waitForSessionFinalization(ctx, target)
174				if err != nil {
175					return nil, nil, fmt.Errorf("session: wait for finalization for %q: %w", target, err)
176				}
177				if !waited {
178					return nil, nil, fmt.Errorf("session: recorder is not available for %q", target)
179				}
180			}
181		}
182	
183		if _, err := m.readMetaWithContext(ctx, target); err != nil {
184			return nil, nil, err
185		}
186	
187		dbPath := store.SessionDBFile(filepath.Join(m.homePaths.SessionsDir, target))
188		if _, err := os.Stat(dbPath); err != nil {
189			if errors.Is(err, os.ErrNotExist) {
190				return nil, nil, fmt.Errorf("%w: %s", ErrSessionNotFound, target)
191			}
192			return nil, nil, fmt.Errorf("session: stat events database for %q: %w", target, err)
193		}
194	
195		recorder, err := m.openStore(ctx, target, dbPath)
196		if err != nil {
197			return nil, nil, fmt.Errorf("session: open events database for %q: %w", target, err)
198		}
199	
200		cleanup := func() error {
201			closeCtx, cancel := context.WithTimeout(context.Background(), defaultLifecycleTimeout)
202			defer cancel()
203			return recorder.Close(closeCtx)
204		}
205		return recorder, cleanup, nil
206	}
207	
208	func (m *Manager) waitForSessionFinalization(ctx context.Context, id string) (bool, error) {
209		target := strings.TrimSpace(id)
210		if target == "" {
211			return false, nil
212		}
213	
214		m.mu.RLock()
215		done, ok := m.finalizing[target]
216		m.mu.RUnlock()
217		if !ok || done == nil {
218			return false, nil
219		}
220	
221		select {
222		case <-done:
223			return true, nil
224		case <-ctx.Done():
225			return true, ctx.Err()
226		}
227	}
228	
229	func (m *Manager) readMetaWithContext(ctx context.Context, id string) (store.SessionMeta, error) {
230		target, err := normalizeStoredSessionID(id)
231		if err != nil {
232			return store.SessionMeta{}, err
233		}
234	
235		metaPath := store.SessionMetaFile(filepath.Join(m.homePaths.SessionsDir, target))
236		meta, err := store.ReadSessionMeta(metaPath)
237		if err != nil {
238			if errors.Is(err, os.ErrNotExist) {
239				return store.SessionMeta{}, fmt.Errorf("%w: %s", ErrSessionNotFound, target)
240			}
241			return store.SessionMeta{}, fmt.Errorf("session: read metadata for %q: %w", target, err)
242		}
243		if _, ok := m.Get(target); ok || m.isPending(target) {
244			return meta, nil
245		}
246		repaired, err := m.repairInactiveMeta(ctx, metaPath, meta)
247		if err != nil {
248			return store.SessionMeta{}, err
249		}
250		return repaired, nil
251	}
252	
253	func normalizeStoredSessionID(id string) (string, error) {
254		target := strings.TrimSpace(id)
255		if target == "" {
256			return "", errors.New("session: session id is required")
257		}
258		if filepath.IsAbs(target) || target == "." || target == ".." {
259			return "", fmt.Errorf("%w: %s", ErrSessionNotFound, target)
260		}
261		if hasWindowsDriveRelativePrefix(target) {
262			return "", fmt.Errorf("%w: %s", ErrSessionNotFound, target)
263		}
264		if strings.Contains(target, "/") || strings.Contains(target, `\`) {
265			return "", fmt.Errorf("%w: %s", ErrSessionNotFound, target)
266		}
267		if filepath.Clean(target) != target {
268			return "", fmt.Errorf("%w: %s", ErrSessionNotFound, target)
269		}
270		return target, nil
271	}
272	
273	func hasWindowsDriveRelativePrefix(value string) bool {
274		if len(value) < 2 || value[1] != ':' {
275			return false
276		}
277		drive := value[0]
278		if (drive < 'a' || drive > 'z') && (drive < 'A' || drive > 'Z') {
279			return false
280		}
281		if len(value) == 2 {
282			return true
283		}
284		return value[2] != '/' && value[2] != '\\'
285	}
