287	func (m *Manager) sessionInfoFromMeta(ctx context.Context, meta store.SessionMeta) *Info {
288		info := sessionInfoFromMeta(meta)
289		workspaceRoot, err := m.resolveWorkspaceRoot(ctx, meta.WorkspaceID)
290		if err != nil {
291			m.logger.Warn(
292				"session: resolve workspace root for metadata failed",
293				"session_id",
294				meta.ID,
295				"workspace_id",
296				meta.WorkspaceID,
297				"error",
298				err,
299			)
300			return info
301		}
302		info.Workspace = workspaceRoot
303		return info
304	}
305	
306	func sessionInfoFromMeta(meta store.SessionMeta) *Info {
307		return &Info{
308			ID:               meta.ID,
309			Name:             meta.Name,
310			AgentName:        meta.AgentName,
311			Provider:         meta.Provider,
312			Model:            strings.TrimSpace(meta.Model),
313			WorkspaceID:      meta.WorkspaceID,
314			Channel:          meta.Channel,
315			Type:             normalizeSessionType(Type(meta.SessionType)),
316			Lineage:          store.NormalizeSessionLineage(meta.ID, meta.Lineage),
317			State:            State(meta.State),
318			StopReason:       sessionMetaStopReason(meta),
319			StopDetail:       meta.StopDetail,
320			Failure:          store.CloneSessionFailure(meta.Failure),
321			ACPSessionID:     stringValue(meta.ACPSessionID),
322			Liveness:         store.CloneSessionLivenessMeta(meta.Liveness),
323			Sandbox:          cloneSessionSandboxMeta(meta.Sandbox),
324			SoulSnapshotID:   strings.TrimSpace(meta.SoulSnapshotID),
325			SoulDigest:       strings.TrimSpace(meta.SoulDigest),
326			ParentSoulDigest: strings.TrimSpace(meta.ParentSoulDigest),
327			CreatedAt:        meta.CreatedAt,
328			UpdatedAt:        meta.UpdatedAt,
329		}
330	}
331	
332	func sortSessionInfos(infos []*Info) []*Info {
333		out := make([]*Info, 0, len(infos))
334		for _, info := range infos {
335			if info == nil {
336				continue
337			}
338			out = append(out, info)
339		}
340	
341		sort.Slice(out, func(i, j int) bool {
342			if out[i].CreatedAt.Equal(out[j].CreatedAt) {
343				return out[i].ID < out[j].ID
344			}
345			return out[i].CreatedAt.Before(out[j].CreatedAt)
346		})
347	
348		return out
349	}
350	
351	func (m *Manager) resolveWorkspaceRoot(ctx context.Context, workspaceID string) (string, error) {
352		if ctx == nil {
353			return "", nil
354		}
355		if strings.TrimSpace(workspaceID) == "" || m.workspace == nil {
356			return "", nil
357		}
358	
359		resolved, err := m.workspace.Resolve(ctx, workspaceID)
360		if err != nil {
361			return "", err
362		}
363		return strings.TrimSpace(resolved.RootDir), nil
364	}
365	
366	func stringValue(value *string) string {
367		if value == nil {
368			return ""
369		}
370		return strings.TrimSpace(*value)
371	}
