138	// OpenSessionDB opens or creates the per-session events database at path.
139	func OpenSessionDB(ctx context.Context, sessionID string, path string) (*SessionDB, error) {
140		if ctx == nil {
141			return nil, errors.New("store: open session database context is required")
142		}
143		if strings.TrimSpace(sessionID) == "" {
144			return nil, errors.New("store: session database session id is required")
145		}
146	
147		db, err := openSessionSQLite(ctx, path)
148		if err != nil {
149			return nil, err
150		}
151	
152		nextSequence, err := currentMaxSequence(ctx, db)
153		if err != nil {
154			_ = db.Close()
155			return nil, fmt.Errorf("store: load current sequence for %q: %w", path, err)
156		}
157	
158		sessionDB := &SessionDB{
159			db:           db,
160			path:         strings.TrimSpace(path),
161			sessionID:    strings.TrimSpace(sessionID),
162			writeCh:      make(chan sessionWriteRequest, defaultWriteBufferSize),
163			shutdownCh:   make(chan sessionShutdownRequest, 1),
164			writerDone:   make(chan struct{}),
165			drainTimeout: defaultDrainTimeout,
166			now: func() time.Time {
167				return time.Now().UTC()
168			},
169			nextSequence: nextSequence,
170		}
171		sessionDB.writerCtx, sessionDB.cancel = context.WithCancel(context.Background())
172		sessionDB.state.Store(sessionStateOpen)
173	
174		go func() {
175			defer close(sessionDB.writerDone)
176			sessionDB.writerLoop()
177		}()
178	
179		return sessionDB, nil
180	}
