198	// Record appends a session event using the dedicated writer goroutine.
199	func (s *SessionDB) Record(ctx context.Context, event store.SessionEvent) error {
200		if s == nil {
201			return errors.New("store: session database is required")
202		}
203		if ctx == nil {
204			return errors.New("store: record event context is required")
205		}
206		if err := event.Validate(); err != nil {
207			return err
208		}
209		if event.SessionID != "" && event.SessionID != s.sessionID {
210			return fmt.Errorf("store: event session id %q does not match session database %q", event.SessionID, s.sessionID)
211		}
212		event.SessionID = s.sessionID
213	
214		return s.enqueueWrite(ctx, sessionWriteRequest{
215			ctx:    ctx,
216			kind:   sessionWriteEvent,
217			event:  event,
218			result: make(chan error, 1),
219		})
