259	// QueryHookRuns returns persisted hook execution records filtered by the supplied options.
260	func (s *SessionDB) QueryHookRuns(ctx context.Context, query store.HookRunQuery) ([]hookspkg.HookRunRecord, error) {
261		if s == nil {
262			return nil, errors.New("store: session database is required")
263		}
264		if ctx == nil {
265			return nil, errors.New("store: query hook runs context is required")
266		}
267		if err := query.Validate(); err != nil {
268			return nil, err
269		}
270		if strings.TrimSpace(query.SessionID) != "" && strings.TrimSpace(query.SessionID) != s.sessionID {
271			return nil, fmt.Errorf(
272				"store: hook run query session id %q does not match session database %q",
273				query.SessionID,
274				s.sessionID,
275			)
276		}
277		if event := strings.TrimSpace(query.Event); event != "" {
278			if err := hookspkg.HookEvent(event).Validate(); err != nil {
279				return nil, err
280			}
281		}
282		if query.Outcome != "" {
283			if err := query.Outcome.Validate(); err != nil {
284				return nil, err
285			}
286		}
287		s.acceptMu.RLock()
288		defer s.acceptMu.RUnlock()
289		if s.state.Load() != sessionStateOpen {
290			return nil, store.ErrClosed
291		}
292	
293		baseQuery := `SELECT
294			rowid, hook_name, event, source, mode, duration_ns, outcome,
295			dispatch_depth, patch_applied, error, required, recorded_at
296			FROM hook_runs`
297		where, args := store.BuildClauses(
298			store.StringClause("event", query.Event),
299			store.StringClause("outcome", string(query.Outcome)),
300			store.TimeClause("recorded_at", ">=", query.Since),
301		)
302		baseQuery = store.AppendWhere(baseQuery, where)
303	
304		sqlQuery := baseQuery
305		if query.Limit > 0 {
306			sqlQuery = `SELECT
307					rowid, hook_name, event, source, mode, duration_ns, outcome,
308					dispatch_depth, patch_applied, error, required, recorded_at
309					FROM (` + baseQuery + ` ORDER BY recorded_at DESC, rowid DESC LIMIT ?) AS recent_hook_runs
310					ORDER BY recorded_at ASC, rowid ASC`
311			args = append(args, query.Limit)
312		} else {
313			sqlQuery += " ORDER BY recorded_at ASC, rowid ASC"
314		}
315	
316		rows, err := s.db.QueryContext(ctx, sqlQuery, args...)
317		if err != nil {
318			return nil, fmt.Errorf("store: query hook runs: %w", err)
319		}
320		defer func() {
321			_ = rows.Close()
322		}()
323	
324		records := make([]hookspkg.HookRunRecord, 0)
325		for rows.Next() {
326			record, scanErr := s.scanHookRunRecord(rows)
327			if scanErr != nil {
328				return nil, scanErr
329			}
330			records = append(records, record)
331		}
332		if err := rows.Err(); err != nil {
333			return nil, fmt.Errorf("store: iterate hook runs: %w", err)
334		}
335	
336		return records, nil
337	}
