356		baseQuery := `SELECT id, sequence, turn_id, type, agent_name, content, timestamp FROM events`
357		where, args := store.BuildClauses(
358			store.StringClause("type", query.Type),
359			store.StringClause("agent_name", query.AgentName),
360			store.StringClause("turn_id", query.TurnID),
361			store.TimeClause("timestamp", ">=", query.Since),
362			store.Int64Clause("sequence", ">", query.AfterSequence),
363		)
