365	
366		sqlQuery := baseQuery
367		if query.Limit > 0 {
368			sqlQuery = `SELECT id, sequence, turn_id, type, agent_name, content, timestamp
369				FROM (` + baseQuery + ` ORDER BY sequence DESC LIMIT ?) AS recent_events
370				ORDER BY sequence ASC`
371			args = append(args, query.Limit)
372		} else {
373			sqlQuery += " ORDER BY sequence ASC"
374		}
375	
376		rows, err := s.db.QueryContext(ctx, sqlQuery, args...)
377		if err != nil {
378			return nil, fmt.Errorf("store: query session events: %w", err)
379		}
380		defer func() {
381			_ = rows.Close()
382		}()
383	
384		events := make([]store.SessionEvent, 0)
385		for rows.Next() {
386			event, scanErr := s.scanSessionEvent(rows)
