399	// History returns ordered session events grouped by turn id.
400	func (s *SessionDB) History(ctx context.Context, query store.EventQuery) ([]store.TurnHistory, error) {
401		events, err := s.Query(ctx, query)
402		if err != nil {
403			return nil, err
404		}
405	
406		turns := make([]store.TurnHistory, 0)
407		indexByTurnID := make(map[string]int, len(events))
408		for _, event := range events {
409			if idx, ok := indexByTurnID[event.TurnID]; ok {
410				turns[idx].Events = append(turns[idx].Events, event)
411				continue
412			}
413	
414			indexByTurnID[event.TurnID] = len(turns)
415			turns = append(turns, store.TurnHistory{
416				TurnID: event.TurnID,
417				Events: []store.SessionEvent{event},
418			})
419		}
420	
421		return turns, nil
422	}
