424	// Close drains queued writes, checkpoints the WAL, and closes the database.
425	func (s *SessionDB) Close(ctx context.Context) error {
426		if s == nil {
427			return nil
428		}
429		if ctx == nil {
430			return errors.New("store: close session database context is required")
431		}
432		if !s.state.CompareAndSwap(sessionStateOpen, sessionStateClosing) {
433			if s.state.Load() == sessionStateClosed {
434				return nil
435			}
436			return store.ErrClosed
437		}
438	
439		drainCtx, cancel := context.WithTimeout(ctx, s.drainTimeout)
440		defer cancel()
441		if s.cancel != nil {
442			defer s.cancel()
443		}
444	
445		s.acceptMu.Lock()
446		resultCh := make(chan error, 1)
447		s.shutdownCh <- sessionShutdownRequest{
448			ctx:    drainCtx,
449			result: resultCh,
450		}
451		s.acceptMu.Unlock()
452	
453		writerErr := waitForShutdownResult(drainCtx, resultCh)
454		writerExitErr := waitForWriterExit(drainCtx, s.writerDone)
455		checkpointErr := store.Checkpoint(drainCtx, s.db)
456		closeErr := s.db.Close()
457	
458		s.state.Store(sessionStateClosed)
459	
460		return errors.Join(writerErr, writerExitErr, checkpointErr, closeErr)
461	}
