463	func (s *SessionDB) enqueueWrite(ctx context.Context, req sessionWriteRequest) error {
464		s.acceptMu.RLock()
465		defer s.acceptMu.RUnlock()
466	
467		if s.state.Load() != sessionStateOpen {
468			return store.ErrClosed
469		}
470	
471		select {
472		case s.writeCh <- req:
473		case <-ctx.Done():
474			return fmt.Errorf("store: enqueue session write: %w", ctx.Err())
475		}
476	
477		select {
478		case err := <-req.result:
479			return err
480		case <-ctx.Done():
481			return fmt.Errorf("store: wait for session write completion: %w", ctx.Err())
482		}
483	}
484	
485	func (s *SessionDB) writerLoop() {
486		for {
487			select {
488			case req := <-s.writeCh:
489				req.result <- s.executeWrite(req)
490			case shutdown := <-s.shutdownCh:
491				shutdown.result <- s.drainWrites(shutdown.ctx)
492				return
493			case <-s.writerCtx.Done():
494				return
495			}
496		}
497	}
498	
499	func (s *SessionDB) drainWrites(ctx context.Context) error {
500		var drainErr error
501	
502		for {
503			select {
504			case <-ctx.Done():
505				return errors.Join(drainErr, fmt.Errorf("%w: %w", store.ErrDrainTimeout, ctx.Err()))
506			case req := <-s.writeCh:
507				err := s.executeWrite(req)
508				req.result <- err
509				if err != nil {
510					drainErr = errors.Join(drainErr, err)
511				}
512			default:
513				return drainErr
514			}
515		}
516	}
517	
518	func (s *SessionDB) executeWrite(req sessionWriteRequest) error {
519		if err := req.ctx.Err(); err != nil {
520			return fmt.Errorf("store: session write canceled before execution: %w", err)
521		}
522	
523		switch req.kind {
524		case sessionWriteEvent:
525			return s.writeEvent(req.ctx, req.event)
526		case sessionWriteUsage:
527			return s.writeTokenUsage(req.ctx, req.usage)
528		case sessionWriteHookRun:
529			return s.writeHookRun(req.ctx, req.hook)
530		default:
531			return fmt.Errorf("store: unsupported session write kind %d", req.kind)
532		}
533	}
