535	func (s *SessionDB) writeEvent(ctx context.Context, event store.SessionEvent) error {
536		if strings.TrimSpace(event.ID) == "" {
537			event.ID = store.NewID("ev")
538		}
539		if event.Timestamp.IsZero() {
540			event.Timestamp = s.now()
541		}
542	
543		s.nextSequence++
544		event.Sequence = s.nextSequence
545	
546		if _, err := s.db.ExecContext(
547			ctx,
548			`INSERT INTO events (id, sequence, turn_id, type, agent_name, content, timestamp)
549			 VALUES (?, ?, ?, ?, ?, ?, ?)`,
550			event.ID,
551			event.Sequence,
552			event.TurnID,
553			event.Type,
554			event.AgentName,
555			event.Content,
556			store.FormatTimestamp(event.Timestamp),
557		); err != nil {
558			s.nextSequence--
559			return fmt.Errorf("store: insert session event: %w", err)
560		}
561	
562		return nil
563	}
