651	func (s *SessionDB) scanSessionEvent(scanner rowScanner) (store.SessionEvent, error) {
652		var (
653			event     store.SessionEvent
654			timestamp string
655		)
656		if err := scanner.Scan(
657			&event.ID,
658			&event.Sequence,
659			&event.TurnID,
660			&event.Type,
661			&event.AgentName,
662			&event.Content,
663			&timestamp,
664		); err != nil {
665			return store.SessionEvent{}, fmt.Errorf("store: scan session event: %w", err)
666		}
667	
668		parsed, err := store.ParseTimestamp(timestamp)
669		if err != nil {
670			return store.SessionEvent{}, err
