677	func (s *SessionDB) scanHookRunRecord(scanner rowScanner) (hookspkg.HookRunRecord, error) {
678		var (
679			record        hookspkg.HookRunRecord
680			rowID         int64
681			event         string
682			source        string
683			mode          string
684			durationNS    int64
685			outcome       string
686			patchApplied  sql.NullString
687			recordError   sql.NullString
688			required      int64
689			recordedAtRaw string
690		)
691	
692		if err := scanner.Scan(
693			&rowID,
694			&record.HookName,
695			&event,
696			&source,
697			&mode,
698			&durationNS,
699			&outcome,
700			&record.DispatchDepth,
701			&patchApplied,
702			&recordError,
703			&required,
704			&recordedAtRaw,
705		); err != nil {
706			return hookspkg.HookRunRecord{}, fmt.Errorf("store: scan hook run: %w", err)
707		}
708	
709		record.Event = hookspkg.HookEvent(strings.TrimSpace(event))
710		if err := record.Event.Validate(); err != nil {
711			return hookspkg.HookRunRecord{}, err
712		}
713		if err := record.Source.UnmarshalText([]byte(strings.TrimSpace(source))); err != nil {
714			return hookspkg.HookRunRecord{}, err
715		}
716		record.Mode = hookspkg.HookMode(strings.TrimSpace(mode))
717		record.Duration = time.Duration(durationNS)
718		record.Outcome = hookspkg.HookRunOutcome(strings.TrimSpace(outcome))
719		record.Required = required != 0
720		record.Error = strings.TrimSpace(recordError.String)
721		if patchApplied.Valid && strings.TrimSpace(patchApplied.String) != "" {
722			record.PatchApplied = json.RawMessage(patchApplied.String)
723		}
724	
725		recordedAt, err := store.ParseTimestamp(recordedAtRaw)
726		if err != nil {
727			return hookspkg.HookRunRecord{}, err
728		}
729		record.RecordedAt = recordedAt
730		_ = rowID
731		return cloneHookRunRecord(record), nil
732	}
