771	type sessionVacuumFunc func(context.Context, *sql.DB) error
772	
773	func openSessionSQLiteWithVacuum(
774		ctx context.Context,
775		path string,
776		vacuumFn sessionVacuumFunc,
777	) (*sql.DB, error) {
778		return store.OpenSQLiteDatabaseWithPragmas(
779			ctx,
780			path,
781			[]string{sessionWALAutoCheckpointPragma},
782			func(ctx context.Context, db *sql.DB) error {
783				if err := store.RunMigrations(ctx, db, sessionSchemaMigrations); err != nil {
784					return err
785				}
786				if vacuumFn == nil {
787					return nil
788				}
789				if err := vacuumFn(ctx, db); err != nil {
790					slog.Default().WarnContext(
791						ctx,
792						"store: skip session sqlite vacuum after non-fatal failure",
793						"path",
794						path,
795						"error",
796						err,
797					)
798				}
799				return nil
800			},
801		)
802	}
