804	func stripCanonicalEventRawPayloads(ctx context.Context, tx *sql.Tx) error {
805		if ctx == nil {
806			return errors.New("store: session raw-strip migration context is required")
807		}
808		if tx == nil {
809			return errors.New("store: session raw-strip migration transaction is required")
810		}
811	
812		if _, err := tx.ExecContext(
813			ctx,
814			`UPDATE events
815			 SET content = json_remove(content, '$.raw')
816			 WHERE json_valid(content) = 1
817			   AND json_extract(content, '$.schema') = ?
818			   AND json_type(content, '$.raw') IS NOT NULL`,
819			canonicalEventSchema,
820		); err != nil {
821			return fmt.Errorf("store: strip canonical session event raw payloads: %w", err)
822		}
823		return nil
824	}
