826	type sqlitePageStats struct {
827		pageCount     int64
828		pageSize      int64
829		freelistCount int64
830	}
831	
832	func vacuumSessionSQLite(ctx context.Context, db *sql.DB) error {
833		stats, err := loadSQLitePageStats(ctx, db)
834		if err != nil {
835			return err
836		}
837		if !shouldVacuumSessionSQLite(stats) {
838			return nil
839		}
840		if _, err := db.ExecContext(ctx, "VACUUM"); err != nil {
841			return fmt.Errorf("store: vacuum session sqlite database: %w", err)
842		}
843		return nil
844	}
845	
846	func loadSQLitePageStats(ctx context.Context, db *sql.DB) (sqlitePageStats, error) {
847		if ctx == nil {
848			return sqlitePageStats{}, errors.New("store: sqlite page stats context is required")
849		}
850		if db == nil {
851			return sqlitePageStats{}, errors.New("store: sqlite page stats database is required")
852		}
853	
854		var stats sqlitePageStats
855		if err := db.QueryRowContext(ctx, "PRAGMA page_count").Scan(&stats.pageCount); err != nil {
856			return sqlitePageStats{}, fmt.Errorf("store: query sqlite page_count: %w", err)
857		}
858		if err := db.QueryRowContext(ctx, "PRAGMA page_size").Scan(&stats.pageSize); err != nil {
859			return sqlitePageStats{}, fmt.Errorf("store: query sqlite page_size: %w", err)
860		}
861		if err := db.QueryRowContext(ctx, "PRAGMA freelist_count").Scan(&stats.freelistCount); err != nil {
862			return sqlitePageStats{}, fmt.Errorf("store: query sqlite freelist_count: %w", err)
863		}
864		return stats, nil
865	}
866	
867	func shouldVacuumSessionSQLite(stats sqlitePageStats) bool {
868		if stats.pageCount <= 0 || stats.pageSize <= 0 || stats.freelistCount <= 0 {
869			return false
870		}
871		freeBytes := stats.freelistCount * stats.pageSize
872		if freeBytes < sessionVacuumMinBytes {
873			return false
874		}
875		return stats.freelistCount*sessionVacuumMinRatio >= stats.pageCount
876	}
