1	import { useEffect, useMemo } from "react";
2	
3	import type { NetworkConversationMessage, NetworkDirectRoomDetail } from "../types";
4	import { useLastRead } from "./use-last-read";
5	import { useNetworkDirectDetail } from "./use-directs";
6	import { useNetworkMessages } from "./use-messages";
7	import { useNetworkPresence, type NetworkPresence } from "./use-network-presence";
8	
9	export interface UseDirectRoomArgs {
10	  channel: string;
11	  directId: string;
12	  selfPeerId?: string;
13	}
14	
15	export interface UseDirectRoomResult {
16	  detail: NetworkDirectRoomDetail | null;
17	  isDetailLoading: boolean;
18	  detailError: Error | null;
19	  messages: NetworkConversationMessage[];
20	  isMessagesLoading: boolean;
21	  messagesError: Error | null;
22	  otherPeerId: string;
23	  presence: NetworkPresence;
24	  lastReadIso: string | null;
25	}
26	
27	function pickOtherPeerId(detail: NetworkDirectRoomDetail | null, selfPeerId?: string): string {
28	  if (!detail) {
29	    return "";
30	  }
31	  if (!selfPeerId) {
32	    return detail.peer_a;
33	  }
34	  return detail.peer_a === selfPeerId ? detail.peer_b : detail.peer_a;
35	}
36	
37	export function useDirectRoom({
38	  channel,
39	  directId,
40	  selfPeerId,
41	}: UseDirectRoomArgs): UseDirectRoomResult {
42	  const detail = useNetworkDirectDetail(channel, directId);
43	  const messagesQuery = useNetworkMessages({
44	    channel,
45	    containerId: directId,
46	    enabled: Boolean(detail.direct),
47	    surface: "direct",
48	  });
49	  const otherPeerId = useMemo(
50	    () => pickOtherPeerId(detail.direct, selfPeerId),
51	    [detail.direct, selfPeerId]
52	  );
53	  const presence = useNetworkPresence({ channel, peerId: otherPeerId });
54	  const { lastReadAt, markRead } = useLastRead();
55	  const lastReadIso = lastReadAt({ channel, containerId: directId, surface: "direct" });
56	
57	  useEffect(() => {
58	    const lastTimestamp = messagesQuery.messages.at(-1)?.timestamp;
59	    if (!lastTimestamp) {
60	      return;
61	    }
62	    markRead({ channel, containerId: directId, surface: "direct" }, lastTimestamp);
63	  }, [channel, directId, markRead, messagesQuery.messages]);
64	
65	  return {
66	    detail: detail.direct,
67	    isDetailLoading: detail.isLoading,
68	    detailError: detail.error,
69	    messages: messagesQuery.messages,
70	    isMessagesLoading: messagesQuery.isLoading,
71	    messagesError: messagesQuery.error,
72	    otherPeerId,
73	    presence,
74	    lastReadIso,
75	  };
76	}
